async (params, browser) => {
  // Open Instagram
  await browser.open('https://www.instagram.com/')

  // Wait for Instagram to load
  await browser.waitForSelector('svg[aria-label=\'Search\'], a[href*=\'explore\'], nav a[href=\'/\']', 15000)

  // Let app fully initialize
  await browser.wait(2000)

  // Click search icon
  const open_search = await browser.evaluate(`const searchLink = document.querySelector('a[href="/explore/"]') || document.querySelector('svg[aria-label="Search"]')?.closest('a') || document.querySelector('svg[aria-label="Search"]')?.closest('div[role="button"]') || Array.from(document.querySelectorAll('svg')).find(s => s.getAttribute('aria-label') === 'Search')?.closest('a, div[role="button"]'); if (searchLink) { searchLink.click(); } return { clicked: !!searchLink }`)

  // Wait for search panel to open
  await browser.wait(1500)

  // Wait for search input
  await browser.waitForSelector('input[aria-label=\'Search input\'], input[placeholder=\'Search\']', 10000)

  // Type search query
  const type_query = await browser.evaluate(`const searchInput = document.querySelector('input[aria-label="Search input"]') || document.querySelector('input[placeholder="Search"]'); if (searchInput) { searchInput.focus(); searchInput.click(); await new Promise(r => setTimeout(r, 300)); searchInput.value = ''; searchInput.dispatchEvent(new Event('input', { bubbles: true })); document.execCommand('insertText', false, params.query); searchInput.dispatchEvent(new Event('input', { bubbles: true })); } return { typed: !!searchInput }`)

  // Wait for search results to load
  await browser.wait(3000)

  // Extract search results
  const search_results = await browser.evaluate(`const results = []; const resultItems = document.querySelectorAll('a[href^="/"][role="link"], div[class*="SearchResult"] a, div[role="none"] a[href^="/"]'); const seen = new Set(); for (const item of resultItems) { if (results.length >= 10) break; const href = item.getAttribute('href') || ''; if (!href || href === '/' || href.startsWith('/explore') || href.startsWith('/accounts') || seen.has(href)) continue; seen.add(href); const imgEl = item.querySelector('img'); const spans = item.querySelectorAll('span'); let username = ''; let fullName = ''; let subtitle = ''; const textParts = []; for (const span of spans) { const text = span.textContent.trim(); if (text && !textParts.includes(text)) textParts.push(text); } if (textParts.length >= 1) username = textParts[0]; if (textParts.length >= 2) fullName = textParts[1]; if (textParts.length >= 3) subtitle = textParts.slice(2).join(' '); if (!username && href) username = href.replace(/\//g, ''); results.push({ username: username, full_name: fullName, subtitle: subtitle, profile_pic: imgEl ? imgEl.src : '', url: 'https://www.instagram.com' + href }); } return { query: params.query, result_count: results.length, results: results }`)

  return search_results
}
